module RefModule (
    input wire clk,
    input wire rst_n,
    input wire d,
    output reg q
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            q <= 0;
        end else begin
            q <= d;
        end
    end
endmodule
